INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-01201', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '乙會計師在決定如何出具本案查核報告時，其態度應為：', '["黃氏家族所為雖生高額損害於大明醫院、彰明醫院，影響限在集團內部，外部影響並非甚鉅，與 一般公開發行公司掏空案件廣泛影響投資大眾權益之情形相異", "大明醫院為社團法人，彰明醫院為財團法人，市立醫院為公立醫院，本案發生後，大明之社員、 彰明之捐助人，以及其他利害關係人未向會計師或衛生署檢舉黃氏家族成員之不當行為，可見黃 氏家族企業之管理違失對外部人影響並非甚鉅", "家族企業本來就是閉鎖型公司，責備、處罰皆應從輕，且本案純屬家族內部利益分配而已", "依據企業個體原則，分別判斷大明醫院、市立醫院、彰明醫院之內外部利害關係人（包括員工、政 府及健保局）法律權責與資訊揭露責任等問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01202', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '小美與小花得知健保署委任乙會計師進行專案查核，二人就委任之性質及該會計師是否應獨立二事 而爭辯，先後發表不同意見。下列諸意見中，何者最適當： 主 人士  看法 張    會計師委任之性質  是否應具獨立性', '["小美  會計師提供財務報表查核之服務  凡會計師執行業務，均應獨立，本案亦不 例外，會計師須獨立", "小花  會計師執行協議程序，查核醫院所失折讓 因委託人健保署為行政機關，本應中立， 利益之金額  故該會計師無獨不獨立的問題，會計師不 須獨立", "小美  就三家醫院是否有舞弊，如何舞弊等，會 凡會計師執行簽證業務，本應獨立，故須 計師出具查核報告  獨立於大明醫療集團之外", "小花  被查核之科目僅醫院的藥品存貨，以及與 會計師應獨立於大明醫療集團及健保署之 該科目有關之交易流程，進行協議程序， 外。 並出具特殊目的查核報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01203', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '會計師首次接受委任查核委任人之財務報表，應向前任會計師查詢有關委任人之資訊，供作是否接 受委任之參考。查詢事項通常不包括：', '["管理階層之品德", "前任會計師與管理階層間對於會計原則、查核程序及其他有關重要事項是否存有歧見", "委任人更換會計師之原因", "繼任會計師向前任會計師借閱工作底稿的條件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01204', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關與受查者管理階層及治理單位溝通之敘述，何者正確？', '["查核人員如已發現存有舞弊，或已取得之資訊顯示可能存有舞弊，則查核人員應儘速與適當之管 理階層溝通", "查核人員如對管理階層或治理單位之誠實與正直存有懷疑，應考量是否尋求該公司之法務主管協 助，以決定採取適當之措施", "查核人員發現受查者基層員工盜用小額公款，即應基於專業判斷與重大性因素考量，而將此事記 錄於工作底稿，不必事事均與管理階層溝通", "查核人員一旦發現在受查者內部控制中扮演重要角色之員工涉及舞弊，僅須與受查者管理階層溝通"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01205', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司於X1年6月將其轉投資公司之股票出售予乙公司，得款10億元，獲利2億元，同時將取得 之10億元以定期存款之方式存放於新加坡ABC銀行。請問，會計師於查核甲公司X1年度財務報表 時，不須考慮下列何種情況？', '["乙公司是否為關係人", "乙公司購買股票資金之來源", "甲公司是否於X1年度內將股票過戶給乙公司", "存放於新加坡ABC銀行之定期存款在使用時是否受有限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01206', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '當查核人員發現客戶之管理階層牽涉到非重大之財務性舞弊時，其責任為何？', '["向受查者治理單位報告舞弊情事", "向金管會證期局報告舞弊情事", "向比牽涉到舞弊的人員至少低一階的管理階層報告舞弊情事", "如果舞弊涉及的金額並不重大，查核人員不須向任何單位或人員報告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01207', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依我國審計準則公報第21號「首次受託－期初餘額之查核」規定，期初餘額之查核範圍不包括下列 何者？', '["前期結轉本期之金額", "前期所採用之會計原則", "前期財務報表之重大誤述", "前期期末已存在之或有事項及承諾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01208', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員自進貨簿隨機選取樣本，追查至應付帳款明細帳的貸方，此種查核方式可以取得的證據為 何？', '["所有進貨交易均屬實在", "已入帳之進貨均已記入應付帳款明細帳", "所有進貨均經適當過入應付帳款明細帳", "凡應付帳款明細帳的貸方交易，均有進貨日記簿的紀錄可加佐證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01209', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何種情況可能不屬於查核範圍受限？', '["受查者部分帳簿憑證因保管不慎而遺失", "主查會計師無法親自查核受查者之國外子公司，而委由當地會計師查核", "受查者表示無法配合提供某些資料，致部分查核程序無法進行", "受查者因採用電子化的程度頗深，部分交易未能保留足夠之交易軌跡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01210', 'cpa', 'cpa-moex-104-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲會計師採用專家報告作為查核證據。下列有關其出具查核報告之敘述，何者錯誤？', '["專家報告所描述之資訊，與財務報表之資訊（相關項目）不一致時，依情況，甲會計師可能出具 保留意見", "甲會計師若出具無保留意見之查核報告，則應在查核報告中提及該專家報告，以共同分攤責任", "該專家報告尚無法作為充分適切之查核證據，依情況，甲會計師可能出具保留意見", "甲會計師依據專家報告出具無保留意見以外之查核報告，適當說明其理由，必要時，經專家同意， 提及專家之身分、參與程度，以及報告之內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:13+00:00", "source_pdf_sha1": "97461eb67326", "answer_pdf_sha1": "3fb81a759858", "source_family": "moex-gov-tw", "moex": {"exam_code": "104130", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "104", "exam_name": "104年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
